import ReactScrollWheelHandler from "react-scroll-wheel-handler"
import React, {Component} from 'react'
import { Link, Element, Events, animateScroll as scroll, scrollSpy, scroller } from 'react-scroll'
import dat from '../dat.json'

const swipeDuration = 700

export default class Inside extends Component {
    state = {
        inside: dat.inside,
        idx: 0,
        direction: 1,
        moving: true,
        from: 0,
        to: 0,
        hasScrolled: false
    }
    textBlocks = {}

    componentDidMount() {
        Events.scrollEvent.register('begin', (to, _) => {
            this.setState({to, from: this.state.to})
        });
        scrollSpy.update();
    }

    componentWillUnmount() {
        Events.scrollEvent.remove('begin');
    }


    render () {
        return <ReactScrollWheelHandler
            upHandler={() => {
                scroller.scrollTo(`${Math.max(0, this.state.to - 1)}`,
                {
                    duration: swipeDuration,
                    smooth: 'easeInOutQuint',
                    containerId: 'scroller',
                })
                if(!this.state.hasScrolled) this.setState({ hasScrolled: true})
            }}
            downHandler={() => {
                scroller.scrollTo(`${Math.min(parseInt(this.state.to) + 1, this.state.inside.length - 1)}`,
                {
                    duration: swipeDuration,
                    delay: 10,
                    smooth: 'easeInOutQuint',
                    containerId: 'scroller',
                })
                if(!this.state.hasScrolled) this.setState({ hasScrolled: true})
            }}
        >
            <span style={{
                position: 'fixed',
                bottom: '4vh',
                left: '4vh',
                transition: "opacity 0.3s",
                WebkitTransition: "opacity 0.3s",
                opacity: this.state.hasScrolled ? 0 : .4,
            }}> SCROLL DOWN </span>
            <div style={{
                height: '90vh',
                width: '20%',
                overflow: 'hidden',
                float: 'left',
                position: 'fixed'
            }}>
                <span style={{
                    top: this.state.from * 3 + 'em',
                    position: 'absolute',
                    width: '100%',
                    backgroundColor: 'black',
                    opacity: .1,
                    height: '3em',
                    zIndex: -1,
                    transform: `translate(0, ${(this.state.to - this.state.from) * 3}em)`,
                    transition: 'all .5s'
                }}/>
                {this.state.inside.map(({title}, i) =>
                    <Link style={{cursor: 'pointer'}}
                        containerId='scroller'
                        to={`${i}`}
                        spy={true}
                        smooth='easeInOutQuint'
                        duration={swipeDuration}
                        ignoreCancelEvents={true}
                        key={`link${i}`}>
                        <div style={{
                            margin: '1vh',
                            padding: '1vh',
                            backgroundColor: this.state.section === 2 ? 'white' : ''
                        }}>
                            {title}
                        </div>
                    </Link>
                )}


            </div>
            <div id='scroller' style={{
                width: '80%',
                height: '90vh',
                position: 'relative',
                overflow: 'hidden',
                float: 'right',
            }}>
                <div>
                        {this.state.inside.map(({img}, idx) =>
                            <Element name={`${idx}`} className="element" style={{
                                width: '100%',
                                height: '88vh'
                            }}>
                                <img src={`images/${img}`} style={{
                                    maxHeight: '99%',
                                    float: 'right',
                                    maxWidth: '80%',
                                }}/>

                            </Element>
                        )}
                    </div>
                    <p>Scroll</p>

            </div>
        </ReactScrollWheelHandler>
    }
}