import React, {Component} from 'react';
import dat from '../dat.json'
import Lightbox from 'react-image-lightbox';
import 'react-image-lightbox/style.css'; // This only needs to be imported once in your app

export default class Gallery extends Component {
    state = {
        gallery: dat.gallery
    }

    componentDidMount() {
        this.listener = document.addEventListener('keydown', (({key}) => key === 'Escape' ? this.setState({clicked: null}) : null))
    }

    componentWillUnmount() {
        document.removeEventListener('keydown', this.listener)
    }

    render() {
        const { photoIndex, isOpen } = this.state;
        const images = this.state.gallery

        return (
            <div style= {{
                width: '99vw',
                animation: 'fade-in 1s'
            }}>
                {this.state.gallery.map((e, i) => <div key={`im${i}`} style={{
                    position: 'relative',
                    float: 'left',
                    width: '20%',
                    height: '20vw',
                }}>
                    <img src={`images/${e}`} style={{
                        width: '95%',
                        height: '95%',
                        margin: '2.5%',
                        objectFit: 'cover',
                        animationDuration: '.6s',
                        animationDelay: `${(Math.floor(i / 5)) / 3}s`,
                        animationName: 'fade-in',
                        animationFillMode: 'both'
                    }}
                        onMouseEnter={() => this.setState({hovered: i})}
                        onMouseLeave={() => this.setState({hovered: null})}
                        onClick={() => this.setState({photoIndex: i, isOpen: true})}
                    />
                </div>)}



                {isOpen && (
                    <Lightbox
                        mainSrc={`images/${images[photoIndex]}`}
                        nextSrc={`images/${images[(photoIndex + 1) % images.length]}`}
                        prevSrc={`images/${images[(photoIndex + images.length - 1) % images.length]}`}
                        onCloseRequest={() => this.setState({ isOpen: false })}
                        onMovePrevRequest={() => this.setState({
                            photoIndex: (photoIndex + images.length - 1) % images.length,
                        })}
                        onMoveNextRequest={() => this.setState({
                            photoIndex: (photoIndex + 1) % images.length,
                        })}
                        animationDuration={750}
                        animationOnKeyInput={true}
                    />
                )}
            </div>
        )
    }
}
